import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken', '')
    try:
        decoded = base64.b64decode(token_str)
    except (TypeError, ValueError):
        return None
    try:
        token_obj = cPickle.loads(decoded)
    except (cPickle.UnpicklingError, EOFError):
        return None
    return token_obj if hasattr(token_obj, 'data') and token_obj.data else None

